You can achieve this in ASP.NET Core API by using the `HttpClient` class to send a request to the target endpoint and then return the response from the target endpoint.

Here's an example of how you can do this:

```csharp
[ApiController]
[Route("api/[controller]")]
public class ProxyController : ControllerBase
{
    private readonly IHttpClientFactory _httpClientFactory;

    public ProxyController(IHttpClientFactory httpClientFactory)
    {
        _httpClientFactory = httpClientFactory;
    }

    [HttpGet]
    public async Task<IActionResult> Get([FromQuery] string targetUrl)
    {
        if (string.IsNullOrEmpty(targetUrl))
        {
            return BadRequest("Target URL is required");
        }

        var client = _httpClientFactory.CreateClient();
        var response = await client.GetAsync(targetUrl);

        if (!response.IsSuccessStatusCode)
        {
            return StatusCode((int)response.StatusCode, await response.Content.ReadAsStringAsync());
        }

        return new ObjectResult(await response.Content.ReadAsStringAsync());
    }
}
```

